import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

describe("mergeIntervals", () => {
  // Bug caught: mishandling the empty base case (e.g. returning undefined).
  it("returns [] for empty input", () => {
    expect(mergeIntervals([])).toEqual([]);
  });

  // Bug caught: a single interval getting dropped or altered.
  it("returns a single interval unchanged", () => {
    expect(mergeIntervals([[1, 5]])).toEqual([[1, 5]]);
  });

  // Bug caught: merging intervals that genuinely overlap.
  it("merges overlapping intervals ([1,4],[3,6] -> [1,6])", () => {
    expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
  });

  // Bug caught: using strict `<` instead of `<=`, failing to merge intervals
  // that only touch at a shared endpoint (the 2==2 boundary).
  it("merges touching intervals ([1,2],[2,3] -> [1,3])", () => {
    expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
  });

  // Bug caught: over-eager merging that fuses a gap. [1,2] ends at 2, [3,4]
  // starts at 3 — one unit apart, must stay separate (just past the boundary).
  it("keeps intervals separate when they are one unit apart ([1,2],[3,4])", () => {
    expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
  });

  // Bug caught: not merging when one interval is fully nested inside another;
  // the result end must be the outer end, not the last-seen inner end.
  it("keeps the larger end when one interval contains another ([1,10],[2,5])", () => {
    expect(mergeIntervals([[1, 10], [2, 5]])).toEqual([[1, 10]]);
  });

  // Bug caught: taking `end` from the later interval instead of Math.max,
  // shrinking the merged interval ([1,10] then [2,5] -> wrongly [1,5]).
  it("does not shrink the end when a contained interval comes second", () => {
    expect(mergeIntervals([[1, 10], [3, 4], [2, 5]])).toEqual([[1, 10]]);
  });

  // Bug caught: failing to sort before merging, so out-of-order input like
  // [4,6],[1,3],[2,5] is not recognized as overlapping.
  it("sorts by start before merging unsorted overlapping input", () => {
    expect(mergeIntervals([[4, 6], [1, 3], [2, 5]])).toEqual([[1, 6]]);
  });

  // Bug caught: output not sorted by start ascending.
  it("returns disjoint intervals sorted by start ascending", () => {
    expect(mergeIntervals([[8, 9], [1, 2], [4, 5]])).toEqual([
      [1, 2],
      [4, 5],
      [8, 9],
    ]);
  });

  // Bug caught: a chain like [1,3],[2,4],[5,7] merging into one blob instead
  // of two, or failing to carry the running end forward across the chain.
  it("merges a transitive chain but preserves a real gap", () => {
    expect(mergeIntervals([[1, 3], [2, 4], [3, 5], [7, 8]])).toEqual([
      [1, 5],
      [7, 8],
    ]);
  });

  // Bug caught: identical duplicate intervals not collapsing to one.
  it("collapses duplicate intervals into one", () => {
    expect(mergeIntervals([[2, 5], [2, 5], [2, 5]])).toEqual([[2, 5]]);
  });

  // Bug caught: zero-length (point) intervals mishandled; two equal points
  // touch at their shared value and must merge.
  it("merges identical zero-length point intervals ([3,3],[3,3] -> [3,3])", () => {
    expect(mergeIntervals([[3, 3], [3, 3]])).toEqual([[3, 3]]);
  });

  // Bug caught: a point interval sitting on another's endpoint not merging.
  it("merges a point interval touching an endpoint ([1,3],[3,3] -> [1,3])", () => {
    expect(mergeIntervals([[1, 3], [3, 3]])).toEqual([[1, 3]]);
  });

  // Bug caught: negative coordinates handled incorrectly by sort/compare.
  it("handles negative-coordinate intervals", () => {
    expect(mergeIntervals([[-5, -1], [-3, 2], [4, 6]])).toEqual([
      [-5, 2],
      [4, 6],
    ]);
  });

  // Bug caught: no validation, or validating the wrong direction. start > end
  // must throw RangeError.
  it("throws RangeError when a pair has start > end", () => {
    expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
  });

  // Bug caught: off-by-one in the guard rejecting a valid start == end pair.
  it("does not throw when start equals end", () => {
    expect(() => mergeIntervals([[4, 4]])).not.toThrow();
  });

  // Bug caught: validation only checking the first element, letting a later
  // inverted pair slip through.
  it("throws when a later pair is inverted even if earlier pairs are valid", () => {
    expect(() => mergeIntervals([[1, 2], [3, 4], [9, 8]])).toThrow(RangeError);
  });

  // Bug caught: mutating the caller's input array.
  it("does not mutate the input array", () => {
    const input = [[1, 4], [3, 6]];
    mergeIntervals(input);
    expect(input).toEqual([[1, 4], [3, 6]]);
  });

  // Bug caught: mutating the inner pair arrays via the running-end update.
  it("does not mutate the input pairs", () => {
    const a = [1, 4];
    const b = [3, 6];
    mergeIntervals([a, b]);
    expect(a).toEqual([1, 4]);
    expect(b).toEqual([3, 6]);
  });

  // Bug caught: returning references into the input rather than a new array.
  it("returns a new array distinct from the input", () => {
    const input = [[1, 4]];
    const result = mergeIntervals(input);
    expect(result).not.toBe(input);
    expect(result[0]).not.toBe(input[0]);
  });
});

